  1	import {
  2	  Button,
  3	  Dropdown,
  4	  DropdownGroup,
  5	  DropdownItem,
  6	  MenuToggle,
  7	  MenuToggleElement,
  8	  OverflowMenu,
  9	  OverflowMenuContent,
 10	  OverflowMenuControl,
 11	  OverflowMenuGroup,
 12	  OverflowMenuItem,
 13	  Toolbar,
 14	  ToolbarItem
 15	} from '@patternfly/react-core';
 16	import { ColumnsIcon, EllipsisVIcon, ExportIcon } from '@patternfly/react-icons';
 17	import React from 'react';
 18	import { useTranslation } from 'react-i18next';
 19	import { FlowScope, MetricType, StatFunction } from '../../model/flow-query';
 20	import { useNetflowContext } from '../../model/netflow-context';
 21	import { TopologyOptions } from '../../model/topology';
 22	import { exportToPng } from '../../utils/export';
 23	import { useTheme } from '../../utils/theme-hook';
 24	import OverviewDisplayDropdown, { Size } from '../dropdowns/overview-display-dropdown';
 25	import TableDisplayDropdown from '../dropdowns/table-display-dropdown';
 26	import TopologyDisplayDropdown from '../dropdowns/topology-display-dropdown';
 27	import { TruncateLength } from '../dropdowns/truncate-dropdown';
 28	import { ViewId } from '../netflow-traffic';
 29	import SearchComponent, { SearchEvent, SearchHandle } from '../search/search';
 30	import './view-options-toolbar.css';
 31	
 32	export interface ViewOptionsToolbarProps {
 33	  overviewFocus: boolean;
 34	  setOverviewFocus: (v: boolean) => void;
 35	  selectedViewId: ViewId;
 36	  setOverviewModalOpen: (v: boolean) => void;
 37	  setColModalOpen: (v: boolean) => void;
 38	  setExportModalOpen: (v: boolean) => void;
 39	  isViewOptionOverflowMenuOpen: boolean;
 40	  setViewOptionOverflowMenuOpen: (v: boolean) => void;
 41	  metricScope: FlowScope;
 42	  setMetricScope: (s: FlowScope) => void;
 43	  overviewTruncateLength: TruncateLength;
 44	  setOverviewTruncateLength: (v: TruncateLength) => void;
 45	  topologyMetricFunction: StatFunction;
 46	  setTopologyMetricFunction: (f: StatFunction) => void;
 47	  topologyMetricType: MetricType;
 48	  setTopologyMetricType: (t: MetricType) => void;
 49	  topologyOptions: TopologyOptions;
 50	  setTopologyOptions: (o: TopologyOptions) => void;
 51	  size: Size;
 52	  setSize: (v: Size) => void;
 53	  showDuplicates: boolean;
 54	  setShowDuplicates: (showDuplicates: boolean) => void;
 55	  setSearchEvent: (se: SearchEvent) => void;
 56	}
 57	
 58	// eslint-disable-next-line react/display-name
 59	export const ViewOptionsToolbar = React.forwardRef<SearchHandle, ViewOptionsToolbarProps>((props, ref) => {
 60	  const { t } = useTranslation('plugin__netobserv-plugin');
 61	  const isDarkTheme = useTheme();
 62	  const { caps } = useNetflowContext();
 63	
 64	  const onTopologyExport = React.useCallback(() => {
 65	    const topology_flex = document.getElementsByClassName('pf-topology-visualization-surface__svg')[0];
 66	    exportToPng('topology', topology_flex as HTMLElement, isDarkTheme);
 67	  }, [isDarkTheme]);
 68	
 69	  const onOverviewExport = React.useCallback(() => {
 70	    const prevFocusState = props.overviewFocus;
 71	    props.setOverviewFocus(false);
 72	    setTimeout(() => {
 73	      const overview_flex = document.getElementById('overview-flex');
 74	      exportToPng('overview_page', overview_flex as HTMLElement, isDarkTheme, undefined, () =>
 75	        props.setOverviewFocus(prevFocusState)
 76	      );
 77	    }, 500);
 78	    // eslint-disable-next-line react-hooks/exhaustive-deps
 79	  }, [isDarkTheme, props.setOverviewFocus]);
 80	
 81	  const viewOptionsContent = () => {
 82	    const items: JSX.Element[] = [];
 83	
 84	    if (props.selectedViewId === 'overview') {
 85	      items.push(
 86	        <OverflowMenuItem key="panels">
 87	          <Button
 88	            data-test="manage-overview-panels-button"
 89	            id="manage-overview-panels-button"
 90	            variant="link"
 91	            className="overflow-button"
 92	            icon={<ColumnsIcon />}
 93	            onClick={() => props.setOverviewModalOpen(true)}
 94	          >
 95	            {t('Manage panels')}
 96	          </Button>
 97	        </OverflowMenuItem>
 98	      );
 99	      items.push(
100	        <OverflowMenuItem key="export">
101	          <Button
102	            data-test="export-button"
103	            id="export-button"
104	            variant="link"
105	            className="overflow-button"
106	            icon={<ExportIcon />}
107	            onClick={() => onOverviewExport()}
108	          >
109	            {t('Export overview')}
110	          </Button>
111	        </OverflowMenuItem>
112	      );
113	    } else if (props.selectedViewId === 'table') {
114	      items.push(
115	        <OverflowMenuItem key="columns">
116	          <Button
117	            data-test="manage-columns-button"
118	            id="manage-columns-button"
119	            variant="link"
120	            className="overflow-button"
121	            icon={<ColumnsIcon />}
122	            onClick={() => props.setColModalOpen(true)}
123	          >
124	            {t('Manage columns')}
125	          </Button>
126	        </OverflowMenuItem>
127	      );
128	      items.push(
129	        <OverflowMenuItem key="export">
130	          <Button
131	            data-test="export-button"
132	            id="export-button"
133	            variant="link"
134	            className="overflow-button"
135	            icon={<ExportIcon />}
136	            onClick={() => props.setExportModalOpen(true)}
137	          >
138	            {t('Export data')}
139	          </Button>
140	        </OverflowMenuItem>
141	      );
142	    } else if (props.selectedViewId === 'topology') {
143	      items.push(
144	        <OverflowMenuItem key="export">
145	          <Button
146	            data-test="export-button"
147	            id="export-button"
148	            variant="link"
149	            className="overflow-button"
150	            icon={<ExportIcon />}
151	            onClick={() => onTopologyExport()}
152	          >
153	            {t('Export topology view')}
154	          </Button>
155	        </OverflowMenuItem>
156	      );
157	    }
158	    return items;
159	  };
160	
161	  const viewOptionsControl = () => {
162	    const dropdownItems: JSX.Element[] = [];
163	
164	    if (props.selectedViewId === 'overview') {
165	      dropdownItems.push(
166	        <DropdownGroup key="panels-group" label={t('Manage')}>
167	          <DropdownItem
168	            key="panels"
169	            id="manage-overview-panels-button"
170	            onClick={() => props.setOverviewModalOpen(true)}
171	          >
172	            {t('Panels')}
173	          </DropdownItem>
174	        </DropdownGroup>
175	      );
176	      dropdownItems.push(
177	        <DropdownGroup key="export-group" label={t('Actions')}>
178	          <DropdownItem key="export" id="export-button" onClick={() => onOverviewExport()}>
179	            {t('Export overview')}
180	          </DropdownItem>
181	        </DropdownGroup>
182	      );
183	    } else if (props.selectedViewId === 'table') {
184	      dropdownItems.push(
185	        <DropdownGroup key="columns-group" label={t('Manage')}>
186	          <DropdownItem key="columns" id="manage-columns-button" onClick={() => props.setColModalOpen(true)}>
187	            {t('Columns')}
188	          </DropdownItem>
189	        </DropdownGroup>
190	      );
191	      dropdownItems.push(
192	        <DropdownGroup key="export-group" label={t('Actions')}>
193	          <DropdownItem key="export" id="export-button" onClick={() => props.setExportModalOpen(true)}>
194	            {t('Export')}
195	          </DropdownItem>
196	        </DropdownGroup>
197	      );
198	    } else if (props.selectedViewId === 'topology') {
199	      dropdownItems.push(
200	        <DropdownGroup key="export-group" label={t('Actions')}>
201	          <DropdownItem key="export" id="export-button" onClick={() => onTopologyExport()}>
202	            {t('Export view')}
203	          </DropdownItem>
204	        </DropdownGroup>
205	      );
206	    }
207	
208	    return (
209	      <Dropdown
210	        data-test="view-options-dropdown"
211	        id="view-options-dropdown"
212	        onSelect={() => props.setViewOptionOverflowMenuOpen(false)}
213	        isOpen={props.isViewOptionOverflowMenuOpen}
214	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
215	          <MenuToggle
216	            ref={toggleRef}
217	            data-test="view-options-button"
218	            id="view-options-button"
219	            variant="plain"
220	            className="overflow-button"
221	            icon={<EllipsisVIcon />}
222	            isExpanded={props.isViewOptionOverflowMenuOpen}
223	            onClick={() => props.setViewOptionOverflowMenuOpen(!props.isViewOptionOverflowMenuOpen)}
224	            onBlur={() => props.setViewOptionOverflowMenuOpen(false)}
225	          >
226	            <>
227	              <EllipsisVIcon /> {t('More options')}
228	            </>
229	          </MenuToggle>
230	        )}
231	      >
232	        {dropdownItems}
233	      </Dropdown>
234	    );
235	  };
236	
237	  return (
238	    <Toolbar data-test-id="view-options-toolbar" id="view-options-toolbar" className={isDarkTheme ? 'dark' : ''}>
239	      <ToolbarItem className="flex-start view-options-first">
240	        <OverflowMenuItem key="display">
241	          {props.selectedViewId === 'overview' && (
242	            <OverviewDisplayDropdown
243	              metricScope={props.metricScope}
244	              setMetricScope={props.setMetricScope}
245	              truncateLength={props.overviewTruncateLength}
246	              setTruncateLength={props.setOverviewTruncateLength}
247	              focus={props.overviewFocus}
248	              setFocus={props.setOverviewFocus}
249	              scopes={caps.availableScopes}
250	            />
251	          )}
252	          {props.selectedViewId === 'table' && (
253	            <TableDisplayDropdown
254	              size={props.size}
255	              setSize={props.setSize}
256	              showDuplicates={props.showDuplicates}
257	              setShowDuplicates={props.setShowDuplicates}
258	            />
259	          )}
260	          {props.selectedViewId === 'topology' && (
261	            <TopologyDisplayDropdown
262	              metricFunction={props.topologyMetricFunction}
263	              setMetricFunction={props.setTopologyMetricFunction}
264	              metricType={props.topologyMetricType}
265	              setMetricType={props.setTopologyMetricType}
266	              metricScope={props.metricScope}
267	              setMetricScope={props.setMetricScope}
268	              topologyOptions={props.topologyOptions}
269	              setTopologyOptions={props.setTopologyOptions}
270	              allowedTypes={caps.allowedMetricTypes}
271	              scopes={caps.availableScopes}
272	            />
273	          )}
274	        </OverflowMenuItem>
275	      </ToolbarItem>
276	      {props.selectedViewId === 'topology' && (
277	        <ToolbarItem className="flex-start" id="search-container" data-test="search-container">
278	          <SearchComponent ref={ref} setSearchEvent={props.setSearchEvent} isDark={isDarkTheme} />
279	        </ToolbarItem>
280	      )}
281	      <ToolbarItem className="flex-start view-options-last" align={{ default: 'alignRight' }}>
282	        <OverflowMenu breakpoint="2xl">
283	          <OverflowMenuContent isPersistent>
284	            <OverflowMenuGroup groupType="button" isPersistent className="view-options-group flex-start">
285	              {viewOptionsContent()}
286	            </OverflowMenuGroup>
287	          </OverflowMenuContent>
288	          <OverflowMenuControl className="flex-start">{viewOptionsControl()}</OverflowMenuControl>
289	        </OverflowMenu>
290	      </ToolbarItem>
291	    </Toolbar>
292	  );
293	});
294	
295	export default ViewOptionsToolbar;

